/**
 * Makes a unary gRPC call with forwarded HTTP headers as metadata.
 */
function makeGrpcCall(client, methodName, requestBody, httpHeaders, timeoutMs = 5000) {
  return new Promise((resolve, reject) => {
    const metadata = createMetadataFromHeaders(httpHeaders);

    // Add gateway identification header
    metadata.add('x-gateway-source', 'api-gateway');
    metadata.add('x-gateway-timestamp', new Date().toISOString());

    const deadline = new Date(Date.now() + timeoutMs);
    const callOptions = { deadline };

    if (typeof client[methodName] !== 'function') {
      return reject(new Error(`Method ${methodName} not found on gRPC client`));
    }

    client[methodName](requestBody, metadata, callOptions, (error, response) => {
      if (error) {
        console.error(`gRPC call to ${methodName} failed:`, {
          code: error.code,
          message: error.message,
          details: error.details,
        });
        return reject(error);
      }
      resolve(response);
    });
  });
}

/**
 * Makes a server-streaming gRPC call with forwarded HTTP headers.
 */
function makeGrpcServerStreamCall(client, methodName, requestBody, httpHeaders, timeoutMs = 30000) {
  return new Promise((resolve, reject) => {
    const metadata = createMetadataFromHeaders(httpHeaders);
    metadata.add('x-gateway-source', 'api-gateway');

    const deadline = new Date(Date.now() + timeoutMs);
    const callOptions = { deadline };

    if (typeof client[methodName] !== 'function') {
      return reject(new Error(`Method ${methodName} not found on gRPC client`));
    }

    const results = [];
    const call = client[methodName](requestBody, metadata, callOptions);

    call.on('data', (data) => {
      results.push(data);
    });

    call.on('error', (error) => {
      console.error(`gRPC stream call to ${methodName} failed:`, {
        code: error.code,
        message: error.message,
      });
      reject(error);
    });

    call.on('end', () => {
      resolve(results);
    });
  });
}

